import SwiftUI
import AppKit
import AIUsagesTrackersLib

struct ChartConfigurationCard: View {
    let preferences: UserDefaultsAppPreferences
    @Bindable var store: UsageStore
    let configurationID: UUID
    let canMoveUp: Bool
    let canMoveDown: Bool
    let onMoveUp: () -> Void
    let onMoveDown: () -> Void
    let onDuplicate: () -> Void
    let onRequestDelete: () -> Void
    let isBeingDragged: Bool
    let dragCoordinateSpace: String
    let onDragChanged: (DragGesture.Value) -> Void
    let onDragEnded: (DragGesture.Value) -> Void

    @State private var isExpanded: Bool = false
    @State private var isHovering: Bool = false

    private var configurationBinding: Binding<ChartConfiguration>? {
        SettingsConfigurationBindings.chartConfiguration(preferences: preferences, configurationID: configurationID)
    }

    var body: some View {
        if let configurationBinding {
            VStack(alignment: .leading, spacing: 0) {
                header(for: configurationBinding.wrappedValue)
                if isExpanded {
                    ChartConfigurationEditor(
                        store: store,
                        configuration: configurationBinding
                    )
                    .padding(.top, 6)
                    .padding(.leading, 30)
                    .padding(.trailing, 4)
                    .padding(.bottom, 10)
                    .transition(
                        .asymmetric(
                            insertion: .opacity.combined(with: .move(edge: .top)),
                            removal: .opacity
                        )
                    )
                }
            }
            .padding(.vertical, 6)
            .background(
                RoundedRectangle(cornerRadius: 8)
                    .fill(rowBackground)
            )
            .overlay(
                RoundedRectangle(cornerRadius: 8)
                    .stroke(Color.secondary.opacity(isExpanded ? 0.22 : 0.0), lineWidth: 1)
            )
            .onHover { isHovering = $0 }
            .contextMenu {
                Button("Duplicate", systemImage: "plus.square.on.square", action: onDuplicate)
                Divider()
                Button("Move up", systemImage: "arrow.up", action: onMoveUp)
                    .disabled(!canMoveUp)
                Button("Move down", systemImage: "arrow.down", action: onMoveDown)
                    .disabled(!canMoveDown)
                Divider()
                Button("Delete", systemImage: "trash", role: .destructive, action: onRequestDelete)
            }
        }
    }

    private var rowBackground: Color {
        if isExpanded { return Color.secondary.opacity(0.07) }
        return isHovering ? Color.secondary.opacity(0.05) : Color.clear
    }

    // MARK: Header

    private func header(for configuration: ChartConfiguration) -> some View {
        HStack(spacing: 8) {
            dragHandle
            disclosureArea(for: configuration)
            actions
        }
        .padding(.horizontal, 8)
    }

    private var dragHandle: some View {
        Image(systemName: "line.3.horizontal")
            .font(.system(size: 11, weight: .semibold))
            .foregroundStyle(isHovering ? Color.secondary : Color.secondary.opacity(0.55))
            .frame(width: 18, height: 28)
            .contentShape(Rectangle())
            .help("Drag to reorder")
            .onHover { hovering in
                if hovering { NSCursor.openHand.push() } else { NSCursor.pop() }
            }
            .gesture(
                DragGesture(minimumDistance: 4, coordinateSpace: .named(dragCoordinateSpace))
                    .onChanged(onDragChanged)
                    .onEnded(onDragEnded)
            )
    }

    private func disclosureArea(for configuration: ChartConfiguration) -> some View {
        HStack(spacing: 8) {
            chevron
            summary(for: configuration)
        }
        .frame(maxWidth: .infinity, alignment: .leading)
        .contentShape(Rectangle())
        .onTapGesture {
            withAnimation(.easeOut(duration: 0.18)) { isExpanded.toggle() }
        }
    }

    private var chevron: some View {
        Image(systemName: "chevron.right")
            .font(.system(size: 10, weight: .semibold))
            .foregroundStyle(.secondary)
            .rotationEffect(.degrees(isExpanded ? 90 : 0))
            .frame(width: 12)
    }

    private func summary(for configuration: ChartConfiguration) -> some View {
        VStack(alignment: .leading, spacing: 2) {
            HStack(spacing: 8) {
                Image(systemName: "chart.xyaxis.line")
                    .font(.callout)
                    .foregroundStyle(.secondary)
                Text(configuration.title.isEmpty ? "Untitled chart" : configuration.title)
                    .font(.body)
                    .fontWeight(.medium)
                    .lineLimit(1)
            }
            HStack(spacing: 6) {
                Text(summaryLabel(for: configuration))
                if case .custom(let series) = configuration.selection, !series.isEmpty {
                    Text("·").foregroundStyle(.tertiary)
                    seriesColorStrip(series: series)
                }
            }
            .font(.caption)
            .foregroundStyle(.secondary)
        }
    }

    private func summaryLabel(for configuration: ChartConfiguration) -> String {
        switch configuration.selection {
        case .allAvailable:
            return "All available metrics"
        case .custom(let series):
            return series.count == 0
                ? "No custom series yet"
                : "\(series.count) custom series"
        }
    }

    private func seriesColorStrip(series: [ChartSeriesConfig]) -> some View {
        HStack(spacing: 2) {
            ForEach(series.prefix(6)) { item in
                Circle()
                    .fill(item.style.color.swiftUIColor)
                    .frame(width: 8, height: 8)
            }
            if series.count > 6 {
                Text("+\(series.count - 6)")
                    .font(.system(size: 9, weight: .medium))
                    .foregroundStyle(.tertiary)
            }
        }
    }

    private var actions: some View {
        HStack(spacing: 2) {
            Button(action: onDuplicate) {
                Image(systemName: "plus.square.on.square")
            }
            .buttonStyle(.borderless)
            .help("Duplicate chart")

            Button(action: onRequestDelete) {
                Image(systemName: "trash")
                    .foregroundStyle(.red)
            }
            .buttonStyle(.borderless)
            .help("Delete chart")
        }
        .opacity(isHovering || isExpanded ? 1.0 : 0.45)
    }
}

import SwiftUI
import AIUsagesTrackersLib

struct ChartSeriesEditor: View {
    @Bindable var store: UsageStore
    @Binding var series: ChartSeriesConfig
    let onDuplicate: () -> Void
    let onDelete: () -> Void

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            headerRow
            MetricSelectionEditor(
                store: store,
                vendor: $series.vendor,
                account: $series.account,
                metricName: $series.metricName,
                layout: .grid
            )
            stylePanel
        }
    }

    private var headerRow: some View {
        HStack(spacing: 8) {
            seriesPreviewLine
            TextField("Series name (optional)", text: $series.label, prompt: Text(defaultSeriesLabel))
                .textFieldStyle(.roundedBorder)
            Button(action: onDuplicate) {
                Image(systemName: "plus.square.on.square")
            }
            .buttonStyle(.borderless)
            .help("Duplicate series")
            Button(action: onDelete) {
                Image(systemName: "trash")
                    .foregroundStyle(.red)
            }
            .buttonStyle(.borderless)
            .help("Delete series")
        }
    }

    private var seriesPreviewLine: some View {
        // Visual stub mirroring how the series will appear in the chart: a short
        // stroked line in the chosen color and style.
        Path { path in
            path.move(to: CGPoint(x: 0, y: 8))
            path.addLine(to: CGPoint(x: 26, y: 8))
        }
        .stroke(series.style.color.swiftUIColor, style: series.style.lineStyle.strokeStyle)
        .frame(width: 26, height: 16)
    }

    // MARK: Style panel

    private var stylePanel: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack(alignment: .center, spacing: 14) {
                styleSubLabel("Color")
                colorSwatches
            }
            HStack(alignment: .center, spacing: 14) {
                styleSubLabel("Line")
                lineStyleChips
            }
        }
        .padding(10)
        .background(
            RoundedRectangle(cornerRadius: 6)
                .fill(Color.secondary.opacity(0.07))
        )
    }

    private func styleSubLabel(_ text: String) -> some View {
        Text(text)
            .font(.caption)
            .foregroundStyle(.secondary)
            .frame(width: 56, alignment: .leading)
    }

    private var colorSwatches: some View {
        HStack(spacing: 6) {
            ForEach(ChartSeriesColor.allCases) { color in
                colorSwatch(color: color)
            }
            Spacer(minLength: 0)
        }
    }

    private func colorSwatch(color: ChartSeriesColor) -> some View {
        let isSelected = series.style.color == color
        return Button {
            withAnimation(.easeOut(duration: 0.12)) {
                series.style.color = color
            }
        } label: {
            ZStack {
                Circle()
                    .strokeBorder(
                        isSelected ? Color.primary.opacity(0.9) : Color.clear,
                        lineWidth: 2
                    )
                    .frame(width: 26, height: 26)
                Circle()
                    .fill(color.swiftUIColor)
                    .frame(width: 18, height: 18)
            }
            .frame(width: 28, height: 28)
            .contentShape(Circle())
        }
        .buttonStyle(.plain)
        .help(color.displayName)
    }

    private var lineStyleChips: some View {
        HStack(spacing: 6) {
            ForEach(ChartLineStyle.allCases) { lineStyle in
                lineStyleChip(style: lineStyle)
            }
            Spacer(minLength: 0)
        }
    }

    private func lineStyleChip(style: ChartLineStyle) -> some View {
        let isSelected = series.style.lineStyle == style
        return Button {
            withAnimation(.easeOut(duration: 0.12)) {
                series.style.lineStyle = style
            }
        } label: {
            ZStack {
                RoundedRectangle(cornerRadius: 6)
                    .fill(isSelected ? Color.accentColor.opacity(0.14) : Color.clear)
                RoundedRectangle(cornerRadius: 6)
                    .strokeBorder(
                        isSelected ? Color.accentColor.opacity(0.85) : Color.secondary.opacity(0.4),
                        lineWidth: 1
                    )
                Path { path in
                    path.move(to: CGPoint(x: 8, y: 13))
                    path.addLine(to: CGPoint(x: 48, y: 13))
                }
                .stroke(series.style.color.swiftUIColor, style: style.strokeStyle)
            }
            .frame(width: 56, height: 26)
            .contentShape(RoundedRectangle(cornerRadius: 6))
        }
        .buttonStyle(.plain)
        .help(style.displayName)
    }

    // MARK: Default label

    private var defaultSeriesLabel: String {
        let accountLabel: String
        switch series.account {
        case .currentlyActive:
            if let entry = store.entries.first(where: { $0.vendor == series.vendor && $0.isActive }) {
                accountLabel = entry.account.rawValue
            } else {
                accountLabel = "currently active"
            }
        case .specific(let email):
            accountLabel = email.rawValue
        }
        return "\(series.vendor.rawValue) / \(accountLabel) / \(series.metricName)"
    }
}

import SwiftUI
import AppKit
import AIUsagesTrackersLib

struct SegmentEditor: View {
    let preferences: any AppPreferences
    @Bindable var store: UsageStore
    let segmentID: UUID
    let isDark: Bool

    private var segmentBinding: Binding<MenuBarSegmentConfig>? {
        SettingsConfigurationBindings.menuBarSegment(preferences: preferences, segmentID: segmentID)
    }

    var body: some View {
        if let segmentBinding {
            VStack(alignment: .leading, spacing: 14) {
                MetricSelectionEditor(
                    store: store,
                    vendor: segmentBinding.vendor,
                    account: segmentBinding.account,
                    metricName: segmentBinding.metricName,
                    layout: .grid,
                    onMetricChanged: { metric in
                        var segment = segmentBinding.wrappedValue
                        segment.display = defaultDisplay(metric: metric, metricName: segment.metricName)
                        segmentBinding.wrappedValue = segment
                    }
                )

                Divider()

                switch segmentBinding.wrappedValue.display {
                case .timeWindow:
                    timeWindowSection(segmentBinding)
                case .payAsYouGo:
                    payAsYouGoSection(segmentBinding)
                }
            }
        }
    }

    // MARK: Section header

    private func sectionTitle(_ text: String) -> some View {
        Text(text)
            .font(.caption2)
            .fontWeight(.semibold)
            .tracking(0.8)
            .textCase(.uppercase)
            .foregroundStyle(.secondary)
    }

    // MARK: Time-window — chip strip + sub-options

    @ViewBuilder
    private func timeWindowSection(_ binding: Binding<MenuBarSegmentConfig>) -> some View {
        let displayBinding = timeWindowDisplayBinding(binding)
        let segment = binding.wrappedValue

        VStack(alignment: .leading, spacing: 10) {
            HStack(spacing: 6) {
                sectionTitle("Menu bar pieces")
                Text("— click a piece to toggle it")
                    .font(.caption2)
                    .foregroundStyle(.tertiary)
            }

            chipStrip(segment: segment, binding: binding, display: displayBinding)

            subOptionsPanel(segment: segment, binding: binding, display: displayBinding)
        }
    }

    // MARK: Chip strip

    @ViewBuilder
    private func chipStrip(
        segment: MenuBarSegmentConfig,
        binding: Binding<MenuBarSegmentConfig>,
        display: Binding<TimeWindowDisplay>
    ) -> some View {
        HStack(alignment: .top, spacing: 6) {
            chip(
                caption: "Icon",
                isOn: display.wrappedValue.showVendorIcon,
                toggle: { display.wrappedValue.showVendorIcon.toggle() }
            ) {
                VendorIconView(vendor: segment.vendor, size: 14)
            }

            chipConnector

            chip(
                caption: "Outage",
                isOn: segment.showOutageWarning,
                toggle: {
                    var seg = binding.wrappedValue
                    seg.showOutageWarning.toggle()
                    binding.wrappedValue = seg
                }
            ) {
                Text(segment.outageWarningText.isEmpty ? "⚠️" : segment.outageWarningText)
                    .font(.system(size: 13))
            }

            chipConnector

            chip(
                caption: "Dot",
                isOn: display.wrappedValue.showDot,
                toggle: { display.wrappedValue.showDot.toggle() }
            ) {
                Circle()
                    .fill(Color.green)
                    .overlay(Circle().stroke(Color.primary.opacity(0.35), lineWidth: 0.6))
                    .frame(width: 9, height: 9)
            }

            chipConnector

            chip(
                caption: "Label",
                isOn: display.wrappedValue.showLetter,
                toggle: { display.wrappedValue.showLetter.toggle() }
            ) {
                Text(display.wrappedValue.letter.isEmpty ? "·" : display.wrappedValue.letter)
                    .font(.system(size: 13, weight: .semibold, design: .monospaced))
            }

            chipConnector

            chip(
                caption: "Percent",
                isOn: display.wrappedValue.showPercent,
                toggle: { display.wrappedValue.showPercent.toggle() }
            ) {
                Text(percentSamplePreview(display: display.wrappedValue))
                    .font(.system(size: 11, weight: .medium, design: .monospaced))
            }

            chipConnector

            chip(
                caption: "Reset",
                isOn: display.wrappedValue.showReset,
                toggle: { display.wrappedValue.showReset.toggle() }
            ) {
                Text(resetSamplePreview(display: display.wrappedValue))
                    .font(.system(size: 11, weight: .medium, design: .monospaced))
            }

            Spacer(minLength: 0)
        }
    }

    private var chipConnector: some View {
        Image(systemName: "chevron.right")
            .font(.system(size: 8, weight: .semibold))
            .foregroundStyle(.tertiary)
            .frame(height: 32)
    }

    private func chip<Symbol: View>(
        caption: String,
        isOn: Bool,
        toggle: @escaping () -> Void,
        @ViewBuilder symbol: () -> Symbol
    ) -> some View {
        Button(action: {
            withAnimation(.easeOut(duration: 0.14)) { toggle() }
        }) {
            VStack(spacing: 4) {
                ZStack {
                    RoundedRectangle(cornerRadius: 6)
                        .fill(isOn ? Color.accentColor.opacity(0.16) : Color.clear)
                    RoundedRectangle(cornerRadius: 6)
                        .strokeBorder(
                            isOn ? Color.accentColor.opacity(0.85) : Color.secondary.opacity(0.45),
                            style: StrokeStyle(
                                lineWidth: 1,
                                dash: isOn ? [] : [3, 2]
                            )
                        )
                    symbol()
                        .opacity(isOn ? 1.0 : 0.4)
                }
                .frame(width: 48, height: 32)
                .contentShape(RoundedRectangle(cornerRadius: 6))

                Text(caption)
                    .font(.system(size: 9, weight: isOn ? .semibold : .regular))
                    .tracking(0.4)
                    .textCase(.uppercase)
                    .foregroundStyle(isOn ? Color.primary : Color.secondary)
            }
        }
        .buttonStyle(.plain)
        .help(isOn ? "\(caption) shown — click to hide" : "\(caption) hidden — click to show")
    }

    private func percentSamplePreview(display: TimeWindowDisplay) -> String {
        switch display.percentDisplayMode {
        case .consumed:  return "42%"
        case .remaining: return "58%"
        }
    }

    private func resetSamplePreview(display: TimeWindowDisplay) -> String {
        // Sample assumes a > 1 day countdown so the toggle's effect is visible.
        // See formatRemainingTime in UsageComputations.swift.
        display.hideResetMinutesWhenOverOneDay ? "2d 4h" : "2d 4h 15m"
    }

    // MARK: Sub-options panel

    @ViewBuilder
    private func subOptionsPanel(
        segment: MenuBarSegmentConfig,
        binding: Binding<MenuBarSegmentConfig>,
        display: Binding<TimeWindowDisplay>
    ) -> some View {
        let hasOutage = segment.showOutageWarning
        let hasLetter = display.wrappedValue.showLetter
        let hasPercent = display.wrappedValue.showPercent
        let hasReset = display.wrappedValue.showReset
        let anyOption = hasOutage || hasLetter || hasPercent || hasReset

        if anyOption {
            VStack(alignment: .leading, spacing: 8) {
                if hasOutage {
                    subOptionRow(label: "Outage text") {
                        TextField("", text: outageTextBinding(binding))
                            .textFieldStyle(.roundedBorder)
                            .frame(width: 64)
                    }
                }
                if hasLetter {
                    subOptionRow(label: "Label letter") {
                        TextField("", text: display.letter)
                            .textFieldStyle(.roundedBorder)
                            .frame(width: 64)
                    }
                }
                if hasPercent {
                    subOptionRow(label: "Percent shows") {
                        Picker("", selection: display.percentDisplayMode) {
                            Text("Consumed").tag(UsagePercentDisplayMode.consumed)
                            Text("Remaining").tag(UsagePercentDisplayMode.remaining)
                        }
                        .labelsHidden()
                        .pickerStyle(.segmented)
                        .frame(width: 200)
                    }
                }
                if hasReset {
                    subOptionRow(label: "Reset format") {
                        Toggle("Hide minutes when over 1 day", isOn: display.hideResetMinutesWhenOverOneDay)
                            .toggleStyle(.checkbox)
                            .fixedSize()
                    }
                }
            }
            .padding(10)
            .background(
                RoundedRectangle(cornerRadius: 6)
                    .fill(Color.secondary.opacity(0.07))
            )
            .transition(.opacity.combined(with: .move(edge: .top)))
        }
    }

    private func subOptionRow<Control: View>(
        label: String,
        @ViewBuilder _ control: () -> Control
    ) -> some View {
        HStack(spacing: 10) {
            Text(label)
                .font(.caption)
                .foregroundStyle(.secondary)
                .frame(width: 100, alignment: .leading)
            control()
            Spacer(minLength: 0)
        }
    }

    // MARK: Pay-as-you-go

    private func payAsYouGoSection(_ binding: Binding<MenuBarSegmentConfig>) -> some View {
        let preview = previewPayAsYouGo(for: binding.wrappedValue) ?? "—"
        return VStack(alignment: .leading, spacing: 10) {
            HStack(spacing: 6) {
                Image(systemName: "info.circle")
                    .foregroundStyle(.secondary)
                Text("Displays \"\(preview)\" — no display pieces to toggle.")
                    .font(.caption)
                    .foregroundStyle(.secondary)
            }
            HStack(spacing: 8) {
                chip(
                    caption: "Outage",
                    isOn: binding.wrappedValue.showOutageWarning,
                    toggle: {
                        var seg = binding.wrappedValue
                        seg.showOutageWarning.toggle()
                        binding.wrappedValue = seg
                    }
                ) {
                    Text(binding.wrappedValue.outageWarningText.isEmpty ? "⚠️" : binding.wrappedValue.outageWarningText)
                        .font(.system(size: 13))
                }
                if binding.wrappedValue.showOutageWarning {
                    TextField("", text: outageTextBinding(binding))
                        .textFieldStyle(.roundedBorder)
                        .frame(width: 64)
                }
            }
        }
    }

    // MARK: Bindings

    private func timeWindowDisplayBinding(
        _ binding: Binding<MenuBarSegmentConfig>
    ) -> Binding<TimeWindowDisplay> {
        Binding<TimeWindowDisplay>(
            get: {
                if case .timeWindow(let d) = binding.wrappedValue.display {
                    return d
                }
                return TimeWindowDisplay()
            },
            set: { newDisplay in
                var seg = binding.wrappedValue
                seg.display = .timeWindow(newDisplay)
                binding.wrappedValue = seg
            }
        )
    }

    private func outageTextBinding(_ binding: Binding<MenuBarSegmentConfig>) -> Binding<String> {
        Binding<String>(
            get: { binding.wrappedValue.outageWarningText },
            set: { newValue in
                var seg = binding.wrappedValue
                seg.outageWarningText = newValue
                binding.wrappedValue = seg
            }
        )
    }

    // MARK: Data helpers

    private func resolveEntry(vendor: Vendor, account: AccountSelection) -> VendorUsageEntry? {
        let vendorEntries = store.entries.filter { $0.vendor == vendor }
        switch account {
        case .currentlyActive:
            return vendorEntries.first(where: { $0.isActive })
        case .specific(let email):
            return vendorEntries.first(where: { $0.account == email })
        }
    }

    private func defaultDisplay(metric: UsageMetric?, metricName: String) -> SegmentDisplay {
        guard let metric else {
            return .timeWindow(TimeWindowDisplay(letter: MenuBarMetricLetter.defaultLetter(for: metricName)))
        }
        switch metric {
        case .payAsYouGo:
            return .payAsYouGo
        case .timeWindow, .unknown:
            return .timeWindow(TimeWindowDisplay(letter: MenuBarMetricLetter.defaultLetter(for: metricName)))
        }
    }

    private func previewPayAsYouGo(for segment: MenuBarSegmentConfig) -> String? {
        guard let entry = resolveEntry(vendor: segment.vendor, account: segment.account),
              let metric = entry.metrics.first(where: { SegmentEditingHelpers.metricName($0) == segment.metricName }),
              case let .payAsYouGo(_, amount, currency) = metric else {
            return nil
        }
        return String(format: "%.2f %@", amount, currency)
    }
}

